CREATE TABLE medicines (id BINARY(16) PRIMARY KEY, name VARCHAR(150) NOT NULL UNIQUE, category VARCHAR(100), unit VARCHAR(30) NOT NULL, min_stock INT NOT NULL DEFAULT 0, active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL);
CREATE TABLE medicine_batches (id BINARY(16) PRIMARY KEY, medicine_id BINARY(16) NOT NULL, lot_number VARCHAR(80) NOT NULL, expiry_date DATE NOT NULL, quantity INT NOT NULL, unit_cost DECIMAL(15,2) NOT NULL DEFAULT 0, created_at TIMESTAMP NOT NULL, CONSTRAINT fk_batch_medicine FOREIGN KEY(medicine_id) REFERENCES medicines(id), CONSTRAINT uk_medicine_lot UNIQUE(medicine_id,lot_number));
CREATE TABLE drug_interactions (id BINARY(16) PRIMARY KEY, medicine_a_id BINARY(16) NOT NULL, medicine_b_id BINARY(16) NOT NULL, severity VARCHAR(20) NOT NULL, description VARCHAR(500) NOT NULL, CONSTRAINT fk_interaction_a FOREIGN KEY(medicine_a_id) REFERENCES medicines(id), CONSTRAINT fk_interaction_b FOREIGN KEY(medicine_b_id) REFERENCES medicines(id));
CREATE TABLE prescriptions (id BINARY(16) PRIMARY KEY, prescription_code VARCHAR(30) NOT NULL UNIQUE, medical_record_id BINARY(16) NOT NULL, doctor_id BINARY(16) NOT NULL, items JSON NOT NULL, warnings JSON, override_reason VARCHAR(500), status VARCHAR(30) NOT NULL, created_at TIMESTAMP NOT NULL, updated_at TIMESTAMP NOT NULL, dispensed_at TIMESTAMP NULL, CONSTRAINT fk_prescription_record FOREIGN KEY(medical_record_id) REFERENCES electronic_medical_records(id), CONSTRAINT fk_prescription_doctor FOREIGN KEY(doctor_id) REFERENCES users(id));
CREATE TABLE inventory_transactions (id BINARY(16) PRIMARY KEY, medicine_id BINARY(16) NOT NULL, batch_id BINARY(16), transaction_type VARCHAR(20) NOT NULL, quantity INT NOT NULL, reference_id BINARY(16), created_at TIMESTAMP NOT NULL, CONSTRAINT fk_inventory_medicine FOREIGN KEY(medicine_id) REFERENCES medicines(id));
